-- (B) Migrate area_cabinets references from dashed to compact format
UPDATE area_cabinets SET product_sku = 'CDB243024' WHERE product_sku = 'CDB-24x30x24-3';
UPDATE area_cabinets SET product_sku = 'CDB304224' WHERE product_sku = 'CDB-30x42x24-4';
UPDATE area_cabinets SET product_sku = 'CDB423024' WHERE product_sku = 'CDB-42x30x24-3';

-- (C) Sanity guard: refuse to delete if any area_cabinets still reference CDB-* SKUs
DO $$
DECLARE leftover INT;
BEGIN
  SELECT COUNT(*) INTO leftover FROM area_cabinets WHERE product_sku LIKE 'CDB-%';
  IF leftover > 0 THEN
    RAISE EXCEPTION 'Refusing to delete: % area_cabinets still reference CDB-* SKUs', leftover;
  END IF;
END $$;

-- (D) Delete the 3 dashed-format duplicates
DELETE FROM products_catalog WHERE sku IN ('CDB-24x30x24-3', 'CDB-30x42x24-4', 'CDB-42x30x24-3');

COMMIT;
